659	  /* ── Global hotkeys: 1–7 modes, ?, V/W/D/M/S/etc tools ─────────────── */
660	  useEffect(() => {
661	    const onKey = (event: globalThis.KeyboardEvent): void => {
662	      const target = event.target as HTMLElement | null;
663	      if (target) {
664	        const tag = target.tagName;
665	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
666	        if (target.isContentEditable) return;
667	      }
668	      const fromMode = modeForHotkey(event.key);
669	      if (fromMode) {
670	        event.preventDefault();
671	        handleModeChange(fromMode);
672	        return;
673	      }
674	      if (event.key === '?') {
675	        event.preventDefault();
676	        setCheatsheetOpen((v) => !v);
677	        return;
678	      }
679	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
680	        event.preventDefault();
681	        setPaletteOpen((v) => !v);
682	        return;
683	      }
684	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
685	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
686	        event.preventDefault();
687	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
688	        return;
689	      }
690	      // Close active tab — Ctrl/⌘+W.
691	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
692	        event.preventDefault();
693	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
694	        return;
695	      }
696	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
697	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
698	        event.preventDefault();
699	        void handleUndoRedo(event.shiftKey ? false : true);
700	        return;
701	      }
702	      // Ortho snap hold on Shift
703	      if (event.shiftKey) setOrthoSnapHold(true);
704	      // Tool hotkeys — match the spec'd letters from TOOL_REGISTRY.
705	      const upper = event.key.length === 1 ? event.key.toUpperCase() : event.key;
706	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
707	      const tool = (Object.values(toolRegistry) as { id: ToolId; hotkey: string }[]).find(
708	        (tool) => tool.hotkey === hotkeyLabel,
709	      );
710	      if (tool) {
711	        const legacy = toolIdToLegacy(tool.id);
712	        if (legacy) {
713	          event.preventDefault();
714	          setPlanTool(legacy);
715	        }
716	      }
717	    };
718	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
719	      if (!event.shiftKey) setOrthoSnapHold(false);
720	    };
721	    document.addEventListener('keydown', onKey);
722	    document.addEventListener('keyup', onKeyUp);
723	    return () => {
724	      document.removeEventListener('keydown', onKey);
725	      document.removeEventListener('keyup', onKeyUp);
726	    };
727	  }, [handleModeChange, handleUndoRedo, setPlanTool, setOrthoSnapHold]);
