  topBar,
  leftRail,
  leftRailCollapsed,
  canvas,
  rightRail,
  statusBar,
  defaultLeftCollapsed = false,
  defaultRightCollapsed = false,
  leftCollapsed: leftCollapsedProp,
  onLeftCollapsedChange,
  hotkeyTarget,
